const prices = [120, 340, 80];
const total = prices.reduce((sum, p) => sum + p, 0);
console.log(total);

List<Integer> prices = Arrays.asList(120, 340, 80);
int total = prices.stream().reduce(0, Integer::sum);
System.out.println(total);

Dim prices As Integer() = {120, 340, 80}
Dim total As Integer = prices.Aggregate(0, Function(sum, p) sum + p)
Debug.Print(total)
